<?php
require_once 'config.php';require_auth();ensure_schema();$pdo=db();$clientId=(int)($_GET['id']??0);$error=null;
function get_client(PDO $pdo,int $id):array{$st=$pdo->prepare('SELECT * FROM clients WHERE id=?');$st->execute([$id]);$c=$st->fetch();if(!$c){http_response_code(404);die('Cliente no encontrado.');}return $c;}
function validate_vehicle(PDO $pdo,string $plate,string $engine,string $chassis,?int $exclude=null):void{$sql='SELECT id FROM vehicles WHERE active=1 AND (plate=? OR engine_number=? OR chassis_number=?)';$p=[$plate,$engine,$chassis];if($exclude){$sql.=' AND id<>?';$p[]=$exclude;}$st=$pdo->prepare($sql.' LIMIT 1');$st->execute($p);if($st->fetch())throw new RuntimeException('Ya existe otra moto activa con la misma patente, motor o chasis.');}
$client=get_client($pdo,$clientId);$pageTitle='Ficha de '.$client['name'];
if(is_post()){try{verify_csrf();$a=(string)post('action');if($a==='update_client'){$name=clean_text(post('name'));$phone=clean_text(post('phone'));if($name===''||$phone==='')throw new RuntimeException('Nombre y teléfono son obligatorios.');$st=$pdo->prepare('UPDATE clients SET name=?,phone=?,email=?,dni=?,address=?,notes=? WHERE id=?');$st->execute([$name,$phone,nullable_text(post('email')),nullable_text(post('dni')),nullable_text(post('address')),nullable_text(post('notes')),$clientId]);flash('success','Cliente actualizado.');}
if(in_array($a,['create_vehicle','update_vehicle'],true)){$vid=$a==='update_vehicle'?(int)post('vehicle_id'):null;$brand=clean_text(post('brand'));$model=clean_text(post('model'));$plate=upper_identifier(post('plate'));$engine=upper_identifier(post('engine_number'));$chassis=upper_identifier(post('chassis_number'));if($brand===''||$model===''||$plate===''||$engine===''||$chassis==='')throw new RuntimeException('Marca, modelo, patente, motor y chasis son obligatorios.');validate_vehicle($pdo,$plate,$engine,$chassis,$vid);$values=[clean_text(post('type'))?:'Moto',$brand,$model,$plate,nullable_text(post('year')),nullable_text(post('cc')),nullable_text(post('color')),$engine,$chassis,int_value(post('km'))];if($a==='create_vehicle'){$st=$pdo->prepare('INSERT INTO vehicles(client_id,type,brand,model,plate,year,cc,color,engine_number,chassis_number,km) VALUES(?,?,?,?,?,?,?,?,?,?,?)');$st->execute(array_merge([$clientId],$values));flash('success','Moto agregada.');}else{$st=$pdo->prepare('UPDATE vehicles SET type=?,brand=?,model=?,plate=?,year=?,cc=?,color=?,engine_number=?,chassis_number=?,km=? WHERE id=? AND client_id=?');$st->execute(array_merge($values,[$vid,$clientId]));flash('success','Moto actualizada.');}}
if(in_array($a,['deactivate_vehicle','restore_vehicle'],true)){$active=$a==='restore_vehicle'?1:0;$st=$pdo->prepare('UPDATE vehicles SET active=? WHERE id=? AND client_id=?');$st->execute([$active,(int)post('vehicle_id'),$clientId]);flash('success',$active?'Moto restaurada.':'Moto archivada sin perder el historial.');}redirect('client_view.php?id='.$clientId);}catch(Throwable $e){$error=$e->getMessage();}}
$client=get_client($pdo,$clientId);$editId=(int)($_GET['edit_vehicle']??0);$edit=null;if($editId){$st=$pdo->prepare('SELECT * FROM vehicles WHERE id=? AND client_id=?');$st->execute([$editId,$clientId]);$edit=$st->fetch()?:null;}$st=$pdo->prepare('SELECT * FROM vehicles WHERE client_id=? ORDER BY active DESC,updated_at DESC');$st->execute([$clientId]);$vehicles=$st->fetchAll();$st=$pdo->prepare('SELECT wo.*,v.brand,v.model,v.plate FROM work_orders wo JOIN vehicles v ON v.id=wo.vehicle_id WHERE wo.client_id=? ORDER BY wo.updated_at DESC');$st->execute([$clientId]);$orders=$st->fetchAll();include 'partials/header.php';?>
<div class="page-head"><div class="page-head-copy"><a class="muted" href="clients.php">← Clientes</a><h1><?=h($client['name'])?></h1><p><?=h($client['phone'])?> · <?=h($client['email']?:'Sin email')?></p></div><div class="actions"><a class="btn btn-primary" href="order_new.php">Nueva orden</a></div></div><?php if($error):?><div class="alert alert-error"><span><?=h($error)?></span></div><?php endif;?><div class="grid">
<section class="card span5"><div class="card-header"><div><h2>Datos del cliente</h2><p>Contacto y referencias.</p></div></div><form method="post" class="form-grid"><?=csrf_field()?><input type="hidden" name="action" value="update_client"><div class="field span6"><label class="required">Nombre</label><input name="name" required value="<?=h($client['name'])?>"></div><div class="field span6"><label class="required">Teléfono</label><input name="phone" required value="<?=h($client['phone'])?>"></div><div class="field span6"><label>Email</label><input type="email" name="email" value="<?=h($client['email'])?>"></div><div class="field span6"><label>DNI</label><input name="dni" value="<?=h($client['dni'])?>"></div><div class="field"><label>Dirección</label><input name="address" value="<?=h($client['address'])?>"></div><div class="field"><label>Notas</label><textarea name="notes"><?=h($client['notes'])?></textarea></div><div class="form-actions"><button class="btn btn-primary">Guardar cambios</button></div></form></section>
<section class="card span7"><div class="card-header"><div><h2><?=$edit?'Editar moto':'Agregar moto'?></h2><p>Patente, motor y chasis siempre en mayúsculas.</p></div><?php if($edit):?><a class="btn btn-sm" href="client_view.php?id=<?=$clientId?>">Cancelar</a><?php endif;?></div><form method="post" class="form-grid"><?=csrf_field()?><input type="hidden" name="action" value="<?=$edit?'update_vehicle':'create_vehicle'?>"><?php if($edit):?><input type="hidden" name="vehicle_id" value="<?=(int)$edit['id']?>"><?php endif;?><div class="field span4"><label>Tipo</label><input name="type" value="<?=h($edit['type']??'Moto')?>"></div><div class="field span4"><label class="required">Marca</label><input name="brand" required value="<?=h($edit['brand']??'')?>"></div><div class="field span4"><label class="required">Modelo</label><input name="model" required value="<?=h($edit['model']??'')?>"></div><div class="field span6"><label class="required">Patente</label><input name="plate" required data-uppercase value="<?=h($edit['plate']??'')?>"></div><div class="field span3"><label>Año</label><input name="year" value="<?=h($edit['year']??'')?>"></div><div class="field span3"><label>Cilindrada</label><input name="cc" value="<?=h($edit['cc']??'')?>"></div><div class="field span6"><label class="required">Número de motor</label><input name="engine_number" required data-uppercase value="<?=h($edit['engine_number']??'')?>"></div><div class="field span6"><label class="required">Número de chasis</label><input name="chassis_number" required data-uppercase value="<?=h($edit['chassis_number']??'')?>"></div><div class="field span6"><label>Color</label><input name="color" value="<?=h($edit['color']??'')?>"></div><div class="field span6"><label>Kilómetros</label><input type="number" min="0" name="km" value="<?=h($edit['km']??'')?>"></div><div class="form-actions"><button class="btn btn-primary"><?=$edit?'Guardar moto':'Agregar moto'?></button></div></form></section>
<section class="card span12"><div class="card-header"><div><h2>Motos registradas</h2><p><?=count($vehicles)?> unidad<?=count($vehicles)===1?'':'es'?></p></div></div><?php if($vehicles):?><div class="table-wrap responsive"><table><thead><tr><th>Moto</th><th>Patente</th><th>Motor</th><th>Chasis</th><th>Datos</th><th>Estado</th><th></th></tr></thead><tbody><?php foreach($vehicles as $v):?><tr><td class="primary-cell"><strong><?=h($v['brand'].' '.$v['model'])?></strong><br><small class="muted"><?=h($v['type'])?></small></td><td data-label="Patente"><strong><?=h($v['plate'])?></strong></td><td data-label="Motor"><?=h($v['engine_number'])?></td><td data-label="Chasis"><?=h($v['chassis_number'])?></td><td data-label="Datos"><?=h(($v['year']?:'S/A').' · '.($v['cc']?:'S/C').' · '.($v['color']?:'S/color'))?></td><td data-label="Estado"><span class="badge <?=$v['active']?'success':'danger'?>"><?=$v['active']?'Activa':'Archivada'?></span></td><td data-label="Acciones"><div class="table-actions"><a class="btn btn-sm" href="client_view.php?id=<?=$clientId?>&edit_vehicle=<?=(int)$v['id']?>">Editar</a><form method="post" data-confirm="<?=$v['active']?'¿Archivar esta moto?':'¿Restaurar esta moto?'?>"><?=csrf_field()?><input type="hidden" name="vehicle_id" value="<?=(int)$v['id']?>"><input type="hidden" name="action" value="<?=$v['active']?'deactivate_vehicle':'restore_vehicle'?>"><button class="btn btn-sm <?=$v['active']?'btn-danger':'btn-success'?>"><?=$v['active']?'Archivar':'Restaurar'?></button></form></div></td></tr><?php endforeach;?></tbody></table></div><?php else:?><div class="empty-state"><div><div class="empty-icon">🏍</div><h2>Sin motos registradas</h2></div></div><?php endif;?></section>
<section class="card span12"><div class="card-header"><div><h2>Historial de órdenes</h2><p>Reparaciones asociadas al cliente.</p></div></div><?php if($orders):?><div class="table-wrap responsive"><table><thead><tr><th>Orden</th><th>Moto</th><th>Estado</th><th>Fecha</th><th>Total</th><th></th></tr></thead><tbody><?php foreach($orders as $o):?><tr><td class="primary-cell"><strong><?=h($o['code'])?></strong></td><td data-label="Moto"><?=h($o['brand'].' '.$o['model'].' · '.$o['plate'])?></td><td data-label="Estado"><span class="status <?=h(status_tone($o['current_status']))?>"><?=h($o['current_status'])?></span></td><td data-label="Fecha"><?=h(date_ar($o['created_at']))?></td><td data-label="Total"><?=h(money($o['total_estimated']))?></td><td data-label="Acción"><a class="btn btn-sm" href="order_view.php?id=<?=(int)$o['id']?>">Abrir</a></td></tr><?php endforeach;?></tbody></table></div><?php else:?><div class="empty-state"><div><div class="empty-icon">01</div><h2>Sin órdenes</h2></div></div><?php endif;?></section></div><?php include 'partials/footer.php';?>
